   372→void ConnPoolImplBase::addIdleCallbackImpl(Instance::IdleCb cb) { idle_callbacks_.push_back(cb); }
   373→
   374→void ConnPoolImplBase::closeIdleConnectionsForDrainingPool() {
   375→  Common::AutoDebugRecursionChecker assert_not_in(recursion_checker_);
   376→
   377→  // Create a separate list of elements to close to avoid mutate-while-iterating problems.
   378→  std::list<ActiveClient*> to_close;
   379→
   380→  for (auto& client : ready_clients_) {
   381→    if (client->numActiveStreams() == 0) {
   382→      to_close.push_back(client.get());
   383→    }
   384→  }
   385→
   386→  if (pending_streams_.empty()) {
   387→    for (auto& client : connecting_clients_) {
   388→      to_close.push_back(client.get());
   389→    }
   390→    for (auto& client : early_data_clients_) {
   391→      if (client->numActiveStreams() == 0) {
   392→        to_close.push_back(client.get());
   393→      }
   394→    }
   395→  }
   396→
   397→  for (auto& entry : to_close) {
   398→    ENVOY_LOG_EVENT(debug, "closing_idle_client", "closing idle client {} for cluster {}",
   399→                    entry->id(), host_->cluster().name());
   400→    entry->close();
   401→  }
   402→}
   403→
   404→void ConnPoolImplBase::drainClients(std::list<ActiveClientPtr>& clients) {
   405→  while (!clients.empty()) {
   406→    ASSERT(clients.front()->numActiveStreams() > 0u);
   407→    ENVOY_LOG_EVENT(
   408→        debug, "draining_non_idle_client", "draining {} client {} for cluster {}",
   409→        (clients.front()->state() == ActiveClient::State::Ready ? "ready" : "early data"),
   410→        clients.front()->id(), host_->cluster().name());
   411→    transitionActiveClientState(*clients.front(), ActiveClient::State::Draining);
   412→  }
   413→}
   414→
   415→void ConnPoolImplBase::drainConnectionsImpl(DrainBehavior drain_behavior) {
   416→  if (drain_behavior == Envoy::ConnectionPool::DrainBehavior::DrainAndDelete) {
   417→    is_draining_for_deletion_ = true;
   418→    checkForIdleAndCloseIdleConnsIfDraining();
   419→    return;
   420→  }
   421→  closeIdleConnectionsForDrainingPool();
   422→  // closeIdleConnectionsForDrainingPool() closes all connections in ready_clients_ with no active
   423→  // streams and if no pending streams, all connections in early_data_clients_ with no active
   424→  // streams as well, so all remaining entries in ready_clients_ are serving streams. Move them and
   425→  // all entries in busy_clients_ to draining.
   426→  if (pending_streams_.empty()) {
   427→    // The remaining early data clients are non-idle.
   428→    drainClients(early_data_clients_);
   429→  }
   430→
   431→  drainClients(ready_clients_);
   432→
   433→  // Changing busy_clients_ to Draining does not move them between lists,
   434→  // so use a for-loop since the list is not mutated.
   435→  ASSERT(&owningList(ActiveClient::State::Draining) == &busy_clients_);
   436→  for (auto& busy_client : busy_clients_) {
   437→    if (busy_client->state() == ActiveClient::State::Draining) {
   438→      continue;
   439→    }
   440→    ENVOY_LOG_EVENT(debug, "draining_busy_client", "draining busy client {} for cluster {}",
   441→                    busy_client->id(), host_->cluster().name());
   442→    transitionActiveClientState(*busy_client, ActiveClient::State::Draining);
   443→  }
   444→}
   445→
   446→bool ConnPoolImplBase::isIdleImpl() const {
   447→  return pending_streams_.empty() && ready_clients_.empty() && busy_clients_.empty() &&
   448→         connecting_clients_.empty() && early_data_clients_.empty();
   449→}
   450→
   451→/*
   452→  This method may be invoked once or twice.
   453→  It is called first time in ConnPoolImplBase::onConnectionEvent for Local/RemoteClose events.
   454→  The second time it is called from Envoy::Tcp::ActiveTcpClient::~ActiveTcpClient via
   455→  ConnPoolImplBase::checkForIdleAndCloseIdleConnsIfDraining.
   456→
   457→  The logic must be constructed in such way that the method is called once or twice.
   458→  See PR 30807 description for explanation why idle callbacks are deleted after being called.
   459→*/
   460→void ConnPoolImplBase::checkForIdleAndNotify() {
   461→  if (isIdleImpl()) {
   462→    ENVOY_LOG(debug, "invoking {} idle callback(s) - is_draining_for_deletion_={}",
   463→              idle_callbacks_.size(), is_draining_for_deletion_);
   464→    for (const Instance::IdleCb& cb : idle_callbacks_) {
   465→      cb();
   466→    }
   467→    // Clear callbacks, so they are not executed if checkForIdleAndNotify is called again.
   468→    idle_callbacks_.clear();
   469→  }
   470→}
   471→
   472→void ConnPoolImplBase::checkForIdleAndCloseIdleConnsIfDraining() {
   473→  if (is_draining_for_deletion_) {
   474→    closeIdleConnectionsForDrainingPool();
   475→  }
   476→
   477→  checkForIdleAndNotify();
   478→}
   479→
   480→void ConnPoolImplBase::onConnectionEvent(ActiveClient& client, absl::string_view failure_reason,
   481→                                         Network::ConnectionEvent event) {
   482→  switch (event) {
   483→  case Network::ConnectionEvent::RemoteClose:
   484→  case Network::ConnectionEvent::LocalClose: {
   485→    if (client.connect_timer_) {
   486→      ASSERT(!client.has_handshake_completed_);
   487→      client.connect_timer_->disableTimer();
   488→      client.connect_timer_.reset();
   489→    }
   490→    decrConnectingAndConnectedStreamCapacity(client.currentUnusedCapacity(), client);
   491→
   492→    // Make sure that onStreamClosed won't double count.
   493→    client.remaining_streams_ = 0;
   494→    // The client died.
   495→    ENVOY_CONN_LOG(debug, "client disconnected, failure reason: {}", client, failure_reason);
   496→
   497→    Envoy::Upstream::reportUpstreamCxDestroy(host_, event);
   498→    const bool incomplete_stream = client.closingWithIncompleteStream();
   499→    if (incomplete_stream) {
   500→      Envoy::Upstream::reportUpstreamCxDestroyActiveRequest(host_, event);
   501→    }
   502→
   503→    if (!client.hasHandshakeCompleted()) {
   504→      client.has_handshake_completed_ = true;
   505→      host_->cluster().trafficStats()->upstream_cx_connect_fail_.inc();
   506→      host_->stats().cx_connect_fail_.inc();
   507→
   508→      onConnectFailed(client);
   509→      // Purge pending streams only if this client doesn't contribute to the local connecting
   510→      // stream capacity. In other words, the rest clients  would be able to handle all the
   511→      // pending stream once they are connected.
   512→      ConnectionPool::PoolFailureReason reason;
   513→      if (client.timed_out_) {
   514→        reason = ConnectionPool::PoolFailureReason::Timeout;
   515→      } else if (event == Network::ConnectionEvent::RemoteClose) {
   516→        reason = ConnectionPool::PoolFailureReason::RemoteConnectionFailure;
   517→      } else {
   518→        reason = ConnectionPool::PoolFailureReason::LocalConnectionFailure;
   519→      }
   520→
   521→      // Raw connect failures should never happen under normal circumstances. If we have an
   522→      // upstream that is behaving badly, streams can get stuck here in the pending state. If we
   523→      // see a connect failure, we purge all pending streams so that calling code can determine
   524→      // what to do with the stream.
   525→      // NOTE: We move the existing pending streams to a temporary list. This is done so that
   526→      //       if retry logic submits a new stream to the pool, we don't fail it inline.
   527→      purgePendingStreams(client.real_host_description_, failure_reason, reason);
   528→      // See if we should preconnect based on active connections.
   529→      if (!is_draining_for_deletion_) {
   530→        tryCreateNewConnections();
   531→      }
   532→    }
   533→
   534→    // We need to release our resourceManager() resources before checking below for
   535→    // whether we can create a new connection. Normally this would happen when
   536→    // client's destructor runs, but this object needs to be deferredDelete'd(), so
   537→    // this forces part of its cleanup to happen now.
   538→    client.releaseResources();
   539→
   540→    // Again, since we know this object is going to be deferredDelete'd(), we take
   541→    // this opportunity to disable and reset the connection duration timer so that
   542→    // it doesn't trigger while on the deferred delete list. In theory it is safe
   543→    // to handle the Closed state in onConnectionDurationTimeout, but we handle
   544→    // it here for simplicity and safety anyway.
   545→    if (client.connection_duration_timer_) {
   546→      client.connection_duration_timer_->disableTimer();
   547→      client.connection_duration_timer_.reset();
   548→    }
   549→
   550→    dispatcher_.deferredDelete(client.removeFromList(owningList(client.state())));
   551→
   552→    // Check if the pool transitioned to idle state after removing closed client
   553→    // from one of the client tracking lists.
   554→    // There is no need to check if other connections are idle in a draining pool
   555→    // because the pool will close all idle connection when it is starting to
   556→    // drain.
   557→    // Trying to close other connections here can lead to deep recursion when
   558→    // a large number idle connections are closed at the start of pool drain.
   559→    // See CdsIntegrationTest.CdsClusterDownWithLotsOfIdleConnections for an example.
   560→    checkForIdleAndNotify();
   561→
   562→    client.setState(ActiveClient::State::Closed);
   563→
   564→    // If we have pending streams and we just lost a connection we should make a new one.
   565→    if (!pending_streams_.empty()) {
   566→      tryCreateNewConnections();
   567→    }
   568→    break;
   569→  }
   570→  case Network::ConnectionEvent::Connected: {
   571→    ASSERT(client.connect_timer_ != nullptr && !client.has_handshake_completed_);
   572→    client.connect_timer_->disableTimer();
   573→    client.connect_timer_.reset();
   574→
   575→    ASSERT(connecting_stream_capacity_ >= client.currentUnusedCapacity());
   576→    connecting_stream_capacity_ -= client.currentUnusedCapacity();
   577→    client.has_handshake_completed_ = true;
   578→    client.conn_connect_ms_->complete();
   579→    client.conn_connect_ms_.reset();
   580→    if (client.state() == ActiveClient::State::Connecting ||
   581→        client.state() == ActiveClient::State::ReadyForEarlyData) {
   582→      transitionActiveClientState(client,
   583→                                  (client.currentUnusedCapacity() > 0 ? ActiveClient::State::Ready
   584→                                                                      : ActiveClient::State::Busy));
   585→    }
   586→
   587→    // Now that the active client is ready, set up a timer for max connection duration.
   588→    const absl::optional<std::chrono::milliseconds> max_connection_duration =
   589→        client.parent_.host()->cluster().maxConnectionDuration();
   590→    if (max_connection_duration.has_value()) {
   591→      client.connection_duration_timer_ = client.parent_.dispatcher().createTimer(
   592→          [&client]() { client.onConnectionDurationTimeout(); });
   593→      client.connection_duration_timer_->enableTimer(max_connection_duration.value());
   594→    }
   595→    // Initialize client read filters
   596→    client.initializeReadFilters();
   597→
   598→    // At this point, for the mixed ALPN pool, the client may be deleted. Do not
   599→    // refer to client after this point.
   600→    onConnected(client);
   601→    if (client.readyForStream()) {
   602→      onUpstreamReady();
   603→    }
   604→    checkForIdleAndCloseIdleConnsIfDraining();
   605→    break;
   606→  }
   607→  case Network::ConnectionEvent::ConnectedZeroRtt: {
   608→    ENVOY_CONN_LOG(debug, "0-RTT connected with capacity {}", client,
   609→                   client.currentUnusedCapacity());
   610→    // No need to update connecting capacity and connect_timer_ as the client is still connecting.
   611→    ASSERT(client.state() == ActiveClient::State::Connecting);
   612→    host()->cluster().trafficStats()->upstream_cx_connect_with_0_rtt_.inc();
   613→    transitionActiveClientState(client, (client.currentUnusedCapacity() > 0
   614→                                             ? ActiveClient::State::ReadyForEarlyData
   615→                                             : ActiveClient::State::Busy));
   616→    break;
   617→  }
   618→  }
   619→}
