   324→
   325→void ConnPoolImplBase::onUpstreamReady() {
   326→  while (!pending_streams_.empty() && !ready_clients_.empty()) {
   327→    ActiveClientPtr& client = ready_clients_.front();
   328→    ENVOY_CONN_LOG(debug, "attaching to next stream", *client);
   329→    // Pending streams are pushed onto the front, so pull from the back.
   330→    attachStreamToClient(*client, pending_streams_.back()->context());
   331→    state_.decrPendingStreams(1);
   332→    pending_streams_.pop_back();
   333→  }
   334→  if (!pending_streams_.empty()) {
   335→    tryCreateNewConnections();
   336→  }
   337→}
   338→
   339→std::list<ActiveClientPtr>& ConnPoolImplBase::owningList(ActiveClient::State state) {
   340→  switch (state) {
   341→  case ActiveClient::State::Connecting:
   342→    return connecting_clients_;
   343→  case ActiveClient::State::ReadyForEarlyData:
   344→    return early_data_clients_;
   345→  case ActiveClient::State::Ready:
   346→    return ready_clients_;
   347→  case ActiveClient::State::Busy:
   348→  case ActiveClient::State::Draining:
   349→    return busy_clients_;
   350→  case ActiveClient::State::Closed:
   351→    break; // Fall through to PANIC.
   352→  }
   353→  PANIC("unexpected");
   354→}
   355→
   356→void ConnPoolImplBase::transitionActiveClientState(ActiveClient& client,
   357→                                                   ActiveClient::State new_state) {
   358→  auto& old_list = owningList(client.state());
   359→  auto& new_list = owningList(new_state);
   360→  client.setState(new_state);
   361→
   362→  // old_list and new_list can be equal when transitioning from Busy to Draining.
   363→  //
   364→  // The documentation for list.splice() (which is what moveBetweenLists() calls) is
   365→  // unclear whether it is allowed for src and dst to be the same, so check here
   366→  // since it is a no-op anyways.
   367→  if (&old_list != &new_list) {
   368→    client.moveBetweenLists(old_list, new_list);
   369→  }
   370→}
