   808→
   809→void ActiveClient::onConnectionDurationTimeout() {
   810→  if (!hasHandshakeCompleted()) {
   811→    // The connection duration timer should only have started after we were connected.
   812→    ENVOY_BUG(false, "max connection duration reached while connecting");
   813→    return;
   814→  }
   815→
   816→  if (state_ == ActiveClient::State::Closed) {
   817→    // The connection duration timer should have been disabled and reset in onConnectionEvent
   818→    // for closing connections.
   819→    ENVOY_BUG(false, "max connection duration reached while closed");
   820→    return;
   821→  }
   822→
   823→  // There's nothing to do if the client is draining.
   824→  if (state_ == ActiveClient::State::Draining) {
   825→    return;
   826→  }
   827→
   828→  ENVOY_CONN_LOG(debug, "max connection duration reached, start draining", *this);
   829→  parent_.host()->cluster().trafficStats()->upstream_cx_max_duration_reached_.inc();
   830→  parent_.transitionActiveClientState(*this, Envoy::ConnectionPool::ActiveClient::State::Draining);
   831→
   832→  // Close out the draining client if we no longer have active streams.
   833→  // We have to do this here because there won't be an onStreamClosed (because there are
   834→  // no active streams) to do it for us later.
   835→  if (numActiveStreams() == 0) {
   836→    close();
   837→  }
   838→}
   839→
   840→void ActiveClient::drain() {
   841→  if (currentUnusedCapacity() <= 0) {
   842→    return;
   843→  }
   844→  parent_.decrConnectingAndConnectedStreamCapacity(currentUnusedCapacity(), *this);
   845→
   846→  remaining_streams_ = 0;
   847→}
